/bin/bash -lc 'cd "$D7_SITE" && ddev drush php-eval '"'
  global "'$user; $user = user_load(1); menu_rebuild();
  $item = menu_get_item("api/healthstats");
  ob_start();
  call_user_func($item["delivery_callback"], call_user_func($item["page_callback"]));
  $out = ob_get_clean();
  echo "delivered body: " . $out . "'"\\n\";
  echo \"content-type header set to JSON via drupal_add_http_header: \";
  "'$h = drupal_get_http_header("Content-Type");
  echo var_export($h, TRUE) . "'"\\n\";
' 2>&1"

